#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');
const crypto = require('crypto');
const path = require('path');

// Validate package.json exists and is valid JSON
function validatePackageJson() {
  const packageJsonPath = path.join(process.cwd(), 'package.json');
  
  if (!fs.existsSync(packageJsonPath)) {
    throw new Error('package.json not found');
  }
  
  try {
    const packageJson = JSON.parse(fs.readFileSync(packageJsonPath, 'utf8'));
    return packageJson;
  } catch (error) {
    throw new Error('Invalid package.json: ' + error.message);
  }
}

// Validate package-lock.json exists for reproducible builds
function validateLockFile() {
  const lockFilePath = path.join(process.cwd(), 'package-lock.json');
  
  if (!fs.existsSync(lockFilePath)) {
    console.warn('WARNING: package-lock.json not found. Builds may not be reproducible.');
    return false;
  }
  
  try {
    JSON.parse(fs.readFileSync(lockFilePath, 'utf8'));
    return true;
  } catch (error) {
    throw new Error('Invalid package-lock.json: ' + error.message);
  }
}

// Verify integrity of package-lock.json against known hash (if provided)
function verifyLockFileIntegrity() {
  const lockFilePath = path.join(process.cwd(), 'package-lock.json');
  const hashFilePath = path.join(process.cwd(), '.package-lock.sha256');
  
  if (fs.existsSync(hashFilePath) && fs.existsSync(lockFilePath)) {
    const expectedHash = fs.readFileSync(hashFilePath, 'utf8').trim();
    const lockFileContent = fs.readFileSync(lockFilePath);
    const actualHash = crypto.createHash('sha256').update(lockFileContent).digest('hex');
    
    if (expectedHash !== actualHash) {
      throw new Error('package-lock.json integrity check failed. File may have been tampered with.');
    }
    console.log('✓ package-lock.json integrity verified');
  }
}

